```csharp
using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.UI;

public class ToastManager : MonoBehaviour
{
    // Configurable properties
    public float displayTime = 2.0f; // Time in seconds to display each toast
    public float fadeTime = 0.5f; // Time in seconds to fade out each toast
    public Text toastText; // Text component for the toast message
    public CanvasGroup canvasGroup; // Canvas group component for the toast panel

    // Internal state
    private Queue<string> messageQueue = new Queue<string>();
    private bool isShowing = false;

    // Start is called before the first frame update
    void Start()
    {
        // Hide the toast panel initially
        canvasGroup.alpha = 0.0f;
        canvasGroup.interactable = false;
        canvasGroup.blocksRaycasts = false;
    }

    // Update is called once per frame
    void Update()
    {
        // Check if there are any messages in the queue and we're not currently showing a toast
        if (messageQueue.Count > 0 && !isShowing)
        {
            // Dequeue the next message and show it
            string message = messageQueue.Dequeue();
            ShowToast(message);
        }
    }

    // Add a message to the queue to display as a toast
    public void ShowMessage(string message)
    {
        messageQueue.Enqueue(message);
    }

    // Show a toast with the given message
    private void ShowToast(string message)
    {
        // Set the text of the toast and show the panel
        toastText.text = message;
        canvasGroup.alpha = 1.0f;
        canvasGroup.interactable = true;
        canvasGroup.blocksRaycasts = true;

        // Start the coroutine to fade out the toast after a delay
        StartCoroutine(FadeOutToast());
    }

    // Coroutine to fade out the toast after a delay
    private IEnumerator FadeOutToast()
    {
        isShowing = true;

        // Wait for the display time to elapse or for the user to tap the toast
        float elapsedTime = 0.0f;
        while (elapsedTime < displayTime)
        {
            if (Input.touchCount > 0 && canvasGroup.alpha == 1.0f)
            {
                // User tapped the toast, so dismiss it immediately
                break;
            }

            elapsedTime += Time.deltaTime;
            yield return null;
        }

        // Fade out the toast over the specified time
        float fadeElapsedTime = 0.0f;
        while (fadeElapsedTime < fadeTime)
        {
            float alpha = Mathf.Lerp(1.0f, 0.0f, fadeElapsedTime / fadeTime);
            canvasGroup.alpha = alpha;

            fadeElapsedTime += Time.deltaTime;
            yield return null;
        }

        // Hide the toast panel and reset internal state
        canvasGroup.alpha = 0.0f;
        canvasGroup.interactable = false;
        canvasGroup.blocksRaycasts = false;
        isShowing = false;
    }
}
```
