define(['N/search', 'N/record', 'N/runtime'], function(search, record, runtime) {

  function getInputData() {
    var customrecord_booking = search.load({
      id: 'customsearch_booking_records',
      type: 'customrecord_booking',
      filters: [['custrecord_booking_date', 'within', 'today'], 'and', ['custrecord_booking_type', 'anyof', '1', '2']],
      columns: ['internalid', 'custrecord_booking_type', 'custrecord_detail_guests']
    });

    return customrecord_booking;
  }

  function map(context) {
    var searchResult = JSON.parse(context.value);
    var bookingId = searchResult.id;
    var bookingType = searchResult.values.custrecord_booking_type[0].value;
    var guests = searchResult.values.custrecord_detail_guests;

    // Get the usual price for the booking type
    var usualPrice;
    if (bookingType === '1') {
      usualPrice = 100;
    } else if (bookingType === '2') {
      usualPrice = 150;
    }

    // Calculate the discount based on the number of guests
    var discount;
    if (guests >= 10) {
      discount = 0.2;
    } else if (guests >= 5) {
      discount = 0.1;
    } else {
      discount = 0;
    }

    // Calculate the discounted price
    var discountedPrice = usualPrice * (1 - discount);

    // Update the booking record with the discounted price
    var bookingRecord = record.load({
      type: 'customrecord_booking',
      id: bookingId
    });

    var newDetail = bookingRecord.getSubrecord({
      fieldId: 'custrecord_booking_detail'
    });

    newDetail.setValue({
      fieldId: 'custrecord_detail_usualrate',
      value: usualPrice
    });

    newDetail.setValue({
      fieldId: 'custrecord_detail_discount',
      value: discount
    });

    newDetail.setValue({
      fieldId: 'custrecord_detail_discountedrate',
      value: discountedPrice
    });

    bookingRecord.save();

    // Log the progress
    log.audit({
      title: 'Processed Booking',
      details: bookingId
    });
  }

  function summarize(summary) {
    // Log the number of records processed
    log.audit({
      title: 'Number of Bookings Processed',
      details: summary.inputSummary.total
    });

    // Check if the script has reached its governance limit
    var usageRemaining = runtime.getCurrentScript().getRemainingUsage();
    log.audit({
      title: 'Script Usage Remaining',
      details: usageRemaining
    });
  }

  return {
    getInputData: getInputData,
    map: map,
    summarize: summarize
  };
});
```
In this version of the script, we have added the `getInputData` function to retrieve the booking records that meet the required filters. We have also updated the `map` function to perform the necessary conditional logic and update the booking record with the discounted price. Finally, we have added the `summarize` function to log the number of records processed and check the script's usage remaining.

